import { NextRequest, NextResponse } from "next/server";
import OpenAI from "openai";
import { readFile, writeFile } from "fs/promises";
import { PdfReader } from "pdfreader";
import path from "path";

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

async function extractTextFromPDF(filePath) {
  return new Promise((resolve, reject) => {
    let text = "";
    new PdfReader().parseFileItems(filePath, (err, item) => {
      if (err) reject(err);
      else if (!item) resolve(text);
      else if (item.text) text += item.text + " ";
    });
  });
}

export async function POST(req) {
  try {
    const formData = await req.formData();
    const file = formData.get("file");

    if (!file || !(file instanceof File)) {
      return NextResponse.json({ message: "Invalid file" }, { status: 400 });
    }

    // Save uploaded file
    const bytes = await file.arrayBuffer();
    const buffer = Buffer.from(bytes);
    const filePath = path.join(process.cwd(), "public/uploads", file.name);
    await writeFile(filePath, buffer);

    // Extract text
    let extractedText = await extractTextFromPDF(filePath);

    // If no text found, use OpenAI API to extract text (OCR fallback)
    if (!extractedText.trim()) {
      const openAiResponse = await openai.chat.completions.create({
        model: "gpt-3.5-turbo",
        messages: [
          {
            role: "system",
            content: "Extract text from the given PDF document.",
          },
          {
            role: "user",
            content: `Extract text from this document: ${filePath}`,
          },
        ],
      });

      extractedText = openAiResponse.choices[0].message.content;
    }

    // Check if the document is a marksheet
    const classificationResponse = await openai.chat.completions.create({
      model: "gpt-3.5-turbo",
      messages: [
        {
          role: "system",
          content:
            "Analyze the extracted text and determine if it's a mark sheet.",
        },
        {
          role: "user",
          content: `Does this text belong to a marksheet? Text: ${extractedText}`,
        },
      ],
    });

    const isMarksheet =
      classificationResponse.choices[0].message.content.includes("Yes");

    return NextResponse.json({
      extractedText,
      isMarksheet,
    });
  } catch (error) {
    console.error("Error processing file:", error);
    return NextResponse.json(
      { message: "Error processing file" },
      { status: 500 }
    );
  }
}
